const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const FIRST_INSURANCE_SURCHARGE = 10;
const PROCESSING_FEE = 5;

export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const basePremium = BASE_PREMIUMS[step.items[0].type];
    const premium =
      Math.ceil(basePremium * (100 + FIRST_INSURANCE_SURCHARGE) / 100) +
      PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

