import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("Claim Office", () => {
  describe("Quoting", () => {
    it("should calculate premium for a single sword (new customer, first insurance)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should calculate correct base premium for each main item type", () => {
      const quote = (type: string) =>
        processScenario({
          customer: { yearsWithMHPCO: 0 },
          steps: [
            {
              op: "quote" as const,
              items: [{ type, material: "steel", enchantment: 0, cursed: false }],
            },
          ],
        }).results[0];

      expect(quote("amulet")).toEqual({ premium: 71 });
      expect(quote("staff")).toEqual({ premium: 93 });
      expect(quote("potion")).toEqual({ premium: 49 });
    });
    it("should calculate premium for a single component", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 33 });
    });
    it("should apply building block premium of 60G for 3 alike components", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it.todo("should add 50% surcharge for cursed items");
    it.todo("should add 30% surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 15% discount on contracts after the first");
    it.todo("should calculate premium for multiple items in one quote");
  });

  describe("Claims", () => {
    it.todo("should apply 100G deductible per damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse highly enchanted items (enchantment >= 8) at 50%");
    it.todo("should fully reimburse damage to dragon material items");
  });

  describe("CLI", () => {
    it.todo("should process a JSON scenario from stdin and write results to stdout");
  });
});

